var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님, 정말 하실 건가요?","JPN":"師匠、本当にやるつもりですか？","ENG":"Are you sure you want to do this, Master?","TWN":"師父，真的要這樣做嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"설마 지금까지 스승님이 해 오신 일들을 잊으신 건 아니겠죠?","JPN":"まさかこれまで師匠がやってきたことを忘れたわけではないですよね？","ENG":"You didn't forget what you've been doing all along, did you?","TWN":"師父不會忘了您一路以來做的事情吧？"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그들</color>이 깨어나는 걸 막기 위해 클리포트 인자 보유자들을 그렇게 사냥해 왔었는데......","JPN":"<color=#ffd34c>彼ら</color>が目覚めるのを阻止するために、クリフォト・ファクター保持者たちを狩ってきましたが……","ENG":"You've spent so much effort hunting down Qliphoth Factor carriers to keep <color=#ffd34c>them</color> from awakening...","TWN":"您為了阻止<color=#ffd34c>他們</color>覺醒，一直在狩獵逆卡巴拉因子擁有者……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정작 스승님께서 그 힘을 개방하는 건 자기모순일 뿐입니다.","JPN":"いざ師匠がその力を開放するのは、自己矛盾でしかありません。","ENG":"You're denying all your past efforts by releasing the power yourself.","TWN":"但要是師父發動這個力量，那就只是自我矛盾而已。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......알고 있다.","JPN":"……わかってる。","ENG":"I know that.","TWN":"……我知道。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이미 <color=#ffd34c>설계도</color>가 되는 원본이 나유빈의 손에 들어간 이상, 이대로 방치하는 건 사태를 악화시킬 뿐이야.","JPN":"だが、<color=#ffd34c>設計図</color>になる原本をイチノセが手に入れた以上、\\nこのまま放置するのは状況を悪化させるだけだ。","ENG":"But the original copy, the one to serve as a <color=#ffd34c>blueprint</color>, has fallen into the hands of Na Yubin. Things will only get worse if I do nothing here.","TWN":"但<color=#ffd34c>設計圖</color>正本已經落入了羅瑜斌的手裡，放任不管只會讓事態惡化而已。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너도 눈치챘겠지?","JPN":"お前も気づいてるだろ？","ENG":"Didn't you notice?","TWN":"妳應該也發現了吧？"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"테라사이드 시스템의 최종목적은 결국 클리포트 인자의 복제체를 만드는 거다.","JPN":"テラサイドシステムの最終目標は、\\nクリフォト・ファクターの複製体を作ることだ。","ENG":"The ultimate goal of System Terraside is to replicate the Qliphoth Factors.","TWN":"特拉賽德系統的最終目標是創造出逆卡巴拉因子的複製體。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이대로 두면 대량으로 생산해 낸 클리포트 레플리카 인자로 놈이 무슨 짓을 할지 몰라.","JPN":"このまま放っておけば、大量に生産した\\nレプリカ・クリフォト・ファクターで奴が何をしでかすかわからない。","ENG":"If we let them be, they will raise all hell with the mass-produced Qliphoth Replica Factors.","TWN":"再這樣下去，不知道那些傢伙們會拿大量生產出來的逆卡巴拉複製因子做些什麼事情。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이미 연쇄반응이 시작된 이상, 사태를 정리하려면 어느 정도 손해를 감수하더라도 압도적인 힘으로 끊어내 버리는 게 상책이다.","JPN":"すでに連鎖反応が始まってしまった以上、この事態を収束するためには\\nある程度のリスクを覚悟のうえで、圧倒的な力で\\n断ち切るしかないだろう。","ENG":"The chain reaction has already started. It's best to put it all to rest quickly with overwhelming strength, although it means we'll have to take some damage.","TWN":"在連鎖反應已經開始的情況下，想要控制事態，就得承受一定的損失，用壓倒性的力量結束這一切才是上策。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 내가 아니면......","JPN":"それに、私以外に……","ENG":"Besides, I'm the only one left here...","TWN":"還有，如果不是我……"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이곳엔 이미 5종 침식체급으로 성장해 버린 저 <color=#ffd34c>테라사이드의 가마솥</color>을 파괴할 자가 없으니까.","JPN":"すでに第5種侵食体級に成長してしまった\\n<color=#ffd34c>テラサイドの釜</color>を破壊できる者は、ここにはいない。","ENG":"who's capable of destroying the <color=#ffd34c>Cauldron of the Terraside</color>, which has become as threatening as a Category 5 C.O.","TWN":"這裡沒有人能夠破壞已經成長為第5級侵蝕體的<color=#ffd34c>特拉賽德之釜</color>。"},"stage":{"bg":"MAINSTREAM_423010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말은 그럴싸하군요.","JPN":"おっしゃることは、もっともらしいですね。","ENG":"You try to make it sound reasonable,","TWN":"聽起來非常有道理。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 설계도의 근본인 미나 양을 처분하지 않는 것만 빼면 말이죠.","JPN":"その設計図の元であるミナさんを処分しないことを除いて。","ENG":"but you haven't done anything with Mina, the very root of the blueprint, have you?","TWN":"除了不處分那個設計圖的根源米娜小姐以外。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구구절절한 이야기를 늘어놓고 계시지만 제가 보기에는 그저 미나 양을 구하러 가기 위한 변명으로밖에는 들리지 않는군요.","JPN":"さっきから長々と話していますが、私にはミナさんを\\n救いに行くための口実にしか聞こえませんね。","ENG":"Every single word you say sound like a mere excuse you're making up to go save Mina.","TWN":"您說了這麼多，在我看來也不過是為了去救米娜小姐的藉口而已。"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 나유빈을 요격하는 대신 여기로 온 것 자체가......","JPN":"そもそも、イチノセ・カオルを迎撃せずに\\nここに来ていること自体が……","ENG":"You coming here instead of launching an attack against Na Yubin was actually—","TWN":"說到底，您不迎擊羅瑜斌，反而來到這裡這件事本身……"},"stage":{"bg":"MAINSTREAM_5505011","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};